```python
import pytest
# Replace import with actual location of your function
from your_module import zip_dicts


class TestZipDicts:
    # ==================================
    # ✅ Happy Path Tests
    # ==================================
    def test_basic_two_dicts_mixed_keys(self):
        """Standard usage: two dicts with overlapping and unique keys"""
        dict_a = {"x": 1, "y": 2}
        dict_b = {"y": 3, "z": 4}

        result = zip_dicts(dict_a, dict_b)

        assert result == {
            "x": [1, None],
            "y": [2, 3],
            "z": [None, 4]
        }

    def test_value_order_matches_input_dicts_order(self):
        """Critical behaviour: list positions strictly match order of input dicts"""
        d1, d2, d3 = {"a": 1}, {"a": 2}, {"a": 3}

        # Forward order
        assert zip_dicts(d1, d2, d3)["a"] == [1, 2, 3]
        # Reverse order inputs produce reversed value lists
        assert zip_dicts(d3, d2, d1)["a"] == [3, 2, 1]

    def test_explicit_none_values_are_preserved(self):
        """Verify explicit stored None values work correctly (not treated as missing)"""
        d1 = {"key": None}
        d2 = {}

        result = zip_dicts(d1, d2)
        assert result["key"] == [None, None]

    def test_three_plus_input_dicts(self):
        """Works correctly for any number of input dicts"""
        d1 = {"foo": "bar"}
        d2 = {"baz": 123}
        d3 = {"foo": "updated", "baz": 456, "extra": True}

        result = zip_dicts(d1, d2, d3)

        assert result["foo"] == ["bar", None, "updated"]
        assert result["baz"] == [None, 123, 456]
        assert result["extra"] == [None, None, True]

    def test_non_string_hashable_keys_supported(self):
        """Works with all valid dict key types, not just strings"""
        d1 = {1: "one", (2, 3): "tuple_key"}
        d2 = {1: "eins"}

        result = zip_dicts(d1, d2)
        assert result[1] == ["one", "eins"]
        assert result[(2, 3)] == ["tuple_key", None]

    # ==================================
    # 🧩 Edge Case Tests
    # ==================================
    def test_zero_input_arguments(self):
        """Calling with no dicts returns empty dict"""
        assert zip_dicts() == {}

    def test_single_input_dict(self):
        """Single dict returns values wrapped in 1-element lists"""
        input_dict = {"a": 1, "b": 2}
        assert zip_dicts(input_dict) == {"a": [1], "b": [2]}

    def test_all_empty_input_dicts(self):
        """All empty inputs return empty output"""
        assert zip_dicts({}, {}, {}) == {}

    def test_mixed_with_empty_dict(self):
        """Empty dict in input sequence correctly injects None values"""
        result = zip_dicts({"x": 10}, {}, {"x": 30})
        assert result["x"] == [10, None, 30]

    @pytest.mark.parametrize("falsy_val", [0, False, "", [], 0.0])
    def test_falsy_values_not_treated_as_missing(self, falsy_val):
        """Falsy actual values are preserved, not replaced with None"""
        result = zip_dicts({"test": falsy_val}, {})
        assert result["test"][0] is falsy_val

    def test_input_dicts_never_mutated(self):
        """Guarantee original input dictionaries are never modified"""
        original = {"a": 1, "b": 2}
        test_copy = original.copy()

        zip_dicts(original, {"c": 3})

        assert original == test_copy

    # ==================================
    # ❌ Error Case Tests
    # ==================================
    @pytest.mark.parametrize("invalid_arg", [
        None, 123, "string", [1, 2], tuple(), set(), object()
    ])
    def test_raises_typeerror_for_non_dict_arguments(self, invalid_arg):
        """Any non-dict input will correctly raise TypeError"""
        with pytest.raises(TypeError):
            zip_dicts({"valid": 1}, invalid_arg)
